check(key: string): { allowed: boolean; remaining: number; resetAt: number } {
  const now = Date.now();
  const entry = this.store.get(key);

  // If no entry exists, create one with count=1
  if (!entry) {
    const resetAt = now + this.config.windowMs;
    this.store.set(key, { count: 1, resetAt });
    return { allowed: true, remaining: this.config.maxRequests - 1, resetAt };
  }

  // If window has expired, reset the counter
  if (now >= entry.resetAt) {
    entry.count = 1;
    entry.resetAt = now + this.config.windowMs;
    this.store.set(key, entry);
    return { allowed: true, remaining: this.config.maxRequests - 1, resetAt: entry.resetAt };
  }

  // If under limit, increment and allow
  if (entry.count < this.config.maxRequests) {
    entry.count++;
    this.store.set(key, entry);
    return { allowed: true, remaining: this.config.maxRequests - entry.count, resetAt: entry.resetAt };
  }

  // If at/over limit, deny
  return { allowed: false, remaining: 0, resetAt: entry.resetAt };
}

cleanup(): number {
  const now = Date.now();
  let removed = 0;
  for (const [key, entry] of this.store.entries()) {
    if (now >= entry.resetAt) {
      this.store.delete(key);
      removed++;
    }
  }
  return removed;
}

reset(key: string): void {
  this.store.delete(key);
}
```

All three methods implemented following existing patterns: check() handles new/expired/under-limit/over-limit cases; cleanup() removes expired entries and returns count; reset() deletes the key for manual override.
